webMI.addEvent("switch", ["click","touchmove"], function(e) {
var id = "switch";
var value = true;
return function(value) {
webMI.data.unsubscribe(subscriptionid); //unsubscribe data when mouse button is pressed (to avoid update 'from field' of the shown variable status)

	if (timeout_id)
		clearTimeout(timeout_id);

	setStatus(!page_status);
	webMI.data.write(webMI.query["base"]+ "", page_status?1:0);
	var realDelay = (delay!=0)?delay*1000:200;

	timeout_id = setTimeout(function(){ //subscribe variable again after "delay" seconds
		subscriptionid = webMI.data.subscribe(webMI.query["base"] + "", function(g) {	
			setStatus(g.value);
		});
	},realDelay);
} (value);
});

function setStatus(status)
{
	var id = "switch";
	if(status==="")
	{
		webMI.gfx.setVisible("disabled_layer", true);		
		status = false;		
	}
	else
		webMI.gfx.setVisible("disabled_layer", false);


	webMI.gfx.setMoveX(id, webMI.translate(status, true, false, 57.9, 0));
	webMI.gfx.setMoveY(id, webMI.translate(status, true, false, 0 , 0));
	if(status)
	{	// set green background color
		webMI.gfx.setFill("bckg_area",c_on);
	}
	else
	{
		// set grey background color
		webMI.gfx.setFill("bckg_area",c_off);
	}
	page_status = status;
}
